package com.example.reportgenerator.storage;
import com.example.reportgenerator.model.*;import com.fasterxml.jackson.databind.ObjectMapper;import com.fasterxml.jackson.databind.SerializationFeature;import org.springframework.stereotype.Service;import java.time.Instant;import java.util.*;
@Service
public class MetadataService { private final ObjectMapper mapper=new ObjectMapper().enable(SerializationFeature.INDENT_OUTPUT);
 public ReportMetadata build(LabReport r,String filename,String xmlSha,String pdfSha,String ts,String xmlPath,String pdfPath){ Map<String,String> dates=new LinkedHashMap<>(); dates.put("creationDate",r.creationDate());dates.put("completionDate",r.completionDate());dates.put("validationDate",r.validationDate());dates.put("prelevementDate",r.prelevementDate());dates.put("specimenDate",r.specimenDate());dates.put("editDate",r.editDate());dates.put("reeditDate",r.reeditDate());dates.put("prescriptionDate",r.prescriptionDate()); return new ReportMetadata(r.referenceNumber(),r.externalNumber(),r.targetLanguage(),filename,xmlSha,pdfSha,ts,xmlPath,pdfPath,r.patient(),r.physician(),dates,r.examinationStatus(),r.accreditation(),r.resultCount(),r.abnormalResultCount(),r.sections(),r.validators(),r.footer(),Map.of("applicationVersion", getClass().getPackage().getImplementationVersion()==null?"dev":getClass().getPackage().getImplementationVersion(),"processedAt", Instant.now().toString(),"status","SUCCESS"));}
 public byte[] json(ReportMetadata m){ try{return mapper.writeValueAsBytes(m);}catch(Exception e){throw new IllegalStateException(e);} }
}
